      backing.DEF_b__h2038 = DEF_b__h2038;
      vcd_write_val(sim_hdl, num++, DEF_b__h2288, 32u);
      backing.DEF_b__h2288 = DEF_b__h2288;
      vcd_write_val(sim_hdl, num++, DEF_b__h2315, 8u);
      backing.DEF_b__h2315 = DEF_b__h2315;
      vcd_write_val(sim_hdl, num++, DEF_b__h2319, 8u);
