      backing.DEF_b__h800 = DEF_b__h800;
      vcd_write_val(sim_hdl, num++, DEF_unsigned_cycle___d6, 8u);
      backing.DEF_unsigned_cycle___d6 = DEF_unsigned_cycle___d6;
